/**
 * @param {string} s
 * @return {number}
 */
function solve(s) {
    const n = s.length;
    let maxLen = 0;

    // Case 1: No swap (0 swaps)
    // We look for the longest balanced substring in the original string s.
    // This is equivalent to finding the longest substring where count('0') == count('1').
    const count = new Array(n + 1).fill(0);
    let prefixCount = 0;
    const diffMap = new Map();
    diffMap.set(0, -1); // Map stores {balance_difference: first_occurrence_index}
    let currentMaxLenNoSwap = 0;

    for (let i = 0; i < n; i++) {
        prefixCount += (s[i] === '1' ? 1 : -1);
        if (diffMap.has(prefixCount)) {
            const j = diffMap.get(prefixCount);
            currentMaxLenNoSwap = Math.max(currentMaxLenNoSwap, i - j);
        } else {
            diffMap.set(prefixCount, i);
        }
    }
    maxLen = Math.max(maxLen, currentMaxLenNoSwap);

    // Case 2: One swap (1 swap)
    // A swap involves changing s[i] and s[j] (i < j).
    // The goal is to maximize the length of a balanced substring in s' (s after swap).
    // Since we can swap *any* two characters, we are effectively allowed to change one '0' to '1' and one '1' to '0'
    // at positions i and j.
    // The net change in the count of '1's in the whole string is 0.
    // Let C0 and C1 be the total counts in s.
    // If we swap s[i] and s[j]:
    // 1. If s[i]='0', s[j]='1' -> s'[i]='1', s'[j]='0'. Total counts are unchanged.
    // 2. If s[i]='0', s[j]='0' -> No change.
    // 3. If s[i]='1', s[j]='1' -> No change.
    // The most beneficial swap is one that changes a '0' to a '1' at position i, and a '1' to a '0' at position j (or vice versa)
    // such that the resulting string allows a longer balanced substring.

    // The core idea derived from competitive programming solutions for this problem structure:
    // The maximum length of a balanced substring after *at most one swap* is determined by
    // finding the longest substring where |count('0') - count('1')| <= 1,
    // *OR* if the total counts allow it, the longest substring where the original imbalance
    // can be corrected by the single swap.

    // A simpler, yet effective, approach:
    // Consider the maximum possible length L. If L is the answer, there exists a balanced substring s'[i..j] of length L.
    // This means count_0(s'[i..j]) = count_1(s'[i..j]) = L/2.
    // L must be even.

    // Since we can swap any two characters, we can transform any string s into a string s' such that
    // the number of '0's and '1's in s' is the same as in s.
    // The maximum possible balanced length is 2 * min(total_0, total_1).

    // The critical observation for this problem is that if the total counts in s are C0 and C1,
    // the maximum length of a balanced substring we can *achieve* is at most 2 * min(C0, C1).
    // If C0 = C1, the answer is N. (If N is even, maxLen = N).
    // If |C0 - C1| = 2, we can swap one character of the majority type with one of the minority type to make C0' = C1' = (N)/2.
    // If |C0 - C1| > 2, we cannot make the total counts equal.

    // Let's check the total counts first.
    let total0 = 0;
    let total1 = 0;
    for (let char of s) {
        if (char === '0') total0++;
        else total1++;
    }

    // If |total0 - total1| <= 2, it's often possible to achieve a very long balanced substring.
    // If |total0 - total1| > 2, the maximum possible balanced length is 2 * min(total0, total1).
    // However, the constraint is on a *substring*, not the whole string.

    // Reverting to the general case: Find the longest substring s[i..j] such that
    // after *at most one swap* within s[i..j] or involving positions outside, the counts become equal.
    // The structure of the problem implies we only need to consider substrings that are 'almost balanced'.

    // A balanced substring s'[i..j] must have length L=j-i+1, and L must be even.
    // Let delta = count_1(s[i..j]) - count_0(s[i..j]). We want the final delta to be 0.
    // The swap can change the delta by at most 2 (e.g., change 0->1 and 1->0 elsewhere, or 0->1 and 0->1 if one position is inside and one outside, which is complex).

    // Simplification based on accepted solutions: The maximum length is determined by the longest substring where the imbalance is at most 2.

    // Case 2.1: Substring s[i..j] where imbalance is 0 or 1 (No swap needed or one swap fixes it optimally).
    // If imbalance is 0, it's covered by Case 1.
    // If imbalance is 1 (e.g., count1 = count0 + 1), we need one '0' to become '1' OR one '1' to become '0'.
    // The swap must involve positions inside the substring.
    // If we have C1 = C0 + 1 (delta = 1), we need to swap a '1' inside with an external '0', or swap an internal '1' with an internal '0' to achieve balance, but that's not guaranteed.

    // The strongest result for "at most one swap" is:
    // Max Length = Max over all substrings s[i..j] of (j-i+1) such that |count_1(s[i..j]) - count_0(s[i..j])| <= 2.

    // If |delta| <= 2, we can always achieve balance with one swap (provided enough characters of the opposite type exist outside/inside).
    // Since the total counts C0 and C1 are fixed, if |C0 - C1| <= 2, we can balance the entire string.

    // We iterate over all possible substrings and check the condition |delta| <= 2.
    // Since O(N^2) is too slow (N=10^5), we use prefix sums (difference tracking) again.

    let currentMaxLenOneSwap = 0;
    const diffMapTwo = new Map(); // Stores {balance_difference: list_of_indices}
    diffMapTwo.set(0, [-1]); // Initialize with a virtual index -1 for empty prefix

    let prefixDiff = 0;

    for (let i = 0; i < n; i++) {
        prefixDiff += (s[i] === '1' ? 1 : -1);

        // Check for existing prefixes j such that |prefixDiff - prefixDiff_j| <= 2
        // i.e., |prefixDiff - (prefixDiff_j)| is -2, -1, 0, 1, or 2.
        // This means prefixDiff_j must be in {prefixDiff - 2, prefixDiff - 1, prefixDiff, prefixDiff + 1, prefixDiff + 2}.

        for (let targetDiff = prefixDiff - 2; targetDiff <= prefixDiff + 2; targetDiff++) {
            if (diffMapTwo.has(targetDiff)) {
                const indices = diffMapTwo.get(targetDiff);
                // If targetDiff is achieved at index j, the substring s[j+1...i] has difference (prefixDiff - targetDiff).
                // The length is i - j.
                for (const j of indices) {
                    // The difference |prefixDiff - targetDiff| is the imbalance of s[j+1..i].
                    // Since we only store indices j where the difference was targetDiff, the imbalance is |prefixDiff - targetDiff|.
                    // We know |prefixDiff - targetDiff| <= 2.
                    currentMaxLenOneSwap = Math.max(currentMaxLenOneSwap, i - j);
                }
            }
        }

        // Add current prefixDiff and index i to the map
        if (!diffMapTwo.has(prefixDiff)) {
            diffMapTwo.set(prefixDiff, []);
        }
        diffMapTwo.get(prefixDiff).push(i);
    }

    maxLen = Math.max(maxLen, currentMaxLenOneSwap);

    return maxLen;
}

