func solve(s string) int64 {
	n := len(s)
	maxLen := int64(0)

	// Case 1: No swap (0 swaps)
	// Longest substring with count('0') == count('1') (difference = 0)
	// PrefixDiff = count('1') - count('0'). We look for PrefixDiff[j] == PrefixDiff[i].
	diffMapNoSwap := make(map[int]int) // Map stores {difference: first_occurrence_index}
	diffMapNoSwap[0] = -1             // Virtual index before the string starts
	prefixCount := 0
	currentMaxLenNoSwap := 0

	for i := 0; i < n; i++ {
		if s[i] == '1' {
			prefixCount++
		} else {
			prefixCount--
		}
		if j, found := diffMapNoSwap[prefixCount]; found {
			currentMaxLenNoSwap = max(currentMaxLenNoSwap, i-j)
		} else {
			diffMapNoSwap[prefixCount] = i
		}
	}
	maxLen = max(maxLen, int64(currentMaxLenNoSwap))

	// Case 2: One swap (1 swap)
	// The maximum length is determined by the longest substring s[i..j] such that
	// |count('1') - count('0')| <= 2 in that substring.
	// This is because if the imbalance is Delta, a single swap (changing one char type to another within the substring)
	// can reduce the imbalance by at most 2, making it achievable if |Delta| <= 2.
	// E.g., if Delta = 3 (3 more '1's), we need to change a '1' to '0' (if available), reducing Delta to 2. If Delta = -3, we need to change a '0' to '1', reducing |Delta| to 2.

	// We look for PrefixDiff[j] such that |PrefixDiff[i] - PrefixDiff[j]| <= 2.
	diffMapOneSwap := make(map[int][]int) // Map stores {difference: list_of_indices}
	diffMapOneSwap[0] = []int{-1}            // Virtual index before the string starts
	prefixDiff := 0
	currentMaxLenOneSwap := 0

	for i := 0; i < n; i++ {
		if s[i] == '1' {
			prefixDiff++
		} else {
			prefixDiff--
		}

		// Target differences j must satisfy |prefixDiff - targetDiff| <= 2
		for targetDiff := prefixDiff - 2; targetDiff <= prefixDiff+2; targetDiff++ {
			if indices, found := diffMapOneSwap[targetDiff]; found {
				for _, j := range indices {
					// Substring s[j+1...i] has imbalance |prefixDiff - targetDiff| <= 2.
					currentMaxLenOneSwap = max(currentMaxLenOneSwap, i-j)
				}
			}
		}

		// Add current prefixDiff and index i to the map
		diffMapOneSwap[prefixDiff] = append(diffMapOneSwap[prefixDiff], i)
	}

	maxLen = max(maxLen, int64(currentMaxLenOneSwap))

	return maxLen
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}
