package main

func solve(s string) int64 {
	n := len(s)
	maxLen := int64(0)

	// Case 1: No swap (0 swaps)
	// Longest substring with balanced counts (diff = 0)
	// Balance: '1' -> +1, '0' -> -1

	// diffMap stores {balance_difference: first_occurrence_index}
