	prefixCount := 0
	currentMaxLenNoSwap := 0

	for i := 0; i < n; i++ {
		if s[i] == '1' {
			prefixCount++
		} else {
			prefixCount--
		}

		if j, found := diffMapNoSwap[prefixCount]; found {
			currentMaxLenNoSwap = max(currentMaxLenNoSwap, i-j)
		} else {
			diffMapNoSwap[prefixCount] = i
		}
	}
	maxLen = int64(max(maxLen, currentMaxLenNoSwap))

	// Case 2: One swap (1 swap)
	// The maximum length achievable is determined by the longest substring s[i..j]
	// such that the imbalance |count('1') - count('0')| <= 2.

