		// Check for targetDiffs such that |prefixDiff - targetDiff| <= 2
		for targetDiff := prefixDiff - 2; targetDiff <= prefixDiff + 2; targetDiff++ {
			if indices, found := diffMapTwo[targetDiff]; found {
				// If targetDiff was achieved at index j, the substring s[j+1...i] has imbalance |prefixDiff - targetDiff| <= 2
				for _, j := range indices {
					currentMaxLenOneSwap = max(currentMaxLenOneSwap, i-j)
				}
			}
